20	const itemPremium = (item: Item): number => {
21	  const base = basePriceOf(item);
22	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
23	  const enchantSurcharge = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
24	  return base + cursedSurcharge + enchantSurcharge;
