27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	const BLOCK_SIZE = 3;
29	const BLOCK_PRICE = 60;
30	
31	const groupByType = (items: Item[]): Map<string, Item[]> => {
32	  const groups = new Map<string, Item[]>();
33	  for (const item of items) {
34	    const existing = groups.get(item.type) ?? [];
35	    existing.push(item);
36	    groups.set(item.type, existing);
37	  }
38	  return groups;
39	};
40	
41	const groupPremium = (type: string, members: Item[]): number => {
42	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
43	  return members.reduce((sum, item) => sum + itemPremium(item), 0);
44	};
45	
46	const itemsSubtotal = (items: Item[]): number =>
47	  Array.from(groupByType(items)).reduce(
48	    (total, [type, members]) => total + groupPremium(type, members),
49	    0,
50	  );
51	
52	const quotePremium = (items: Item[]): number =>
53	  itemsSubtotal(items) + PROCESSING_FEE;
54	
55	const runStep = (step: QuoteStep): StepResult => ({
56	  premium: quotePremium(step.items),
57	});
58	
59	export const runScenario = (input: Scenario): ScenarioResult => ({
60	  results: input.steps.map(runStep),
61	});
